mapper.update:
UPDATE messenger_data

   SET is_read = 'Y'

 WHERE room_no = #{room_no}

   AND sender_id != #{user_id}

   AND is_read = 'N'

mapper.select:
SELECT
m.nickname
FROM messenger_member mm
JOIN member m ON mm.user_id = m.id
WHERE mm.room_no = #{room_no}
AND mm.user_id != #{user_id}

SELECT COUNT(*)

FROM messenger_data

WHERE room_no IN (

    SELECT room_no
    FROM messenger_member
    WHERE user_id = #{user_id}

)

  AND sender_id != #{user_id}

  AND is_read = 'N'
